95	func (f *CommandFactory) resolveCommitSHA(commitSHA string) (string, error) {
96		if commitSHA == "" {
97			return "", nil
98		}
99	
100		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
101		defer cancel()
102	
103		repoDir := f.WorkingDir
104		if repoDir == "" {
105			repoDir = "."
106		}
107	
108		if isFullCommitSHA(commitSHA) && !gitpkg.IsRepository(repoDir) {
109			return commitSHA, nil
110		}
111	
112		cmd := exec.CommandContext(ctx, "git", "-C", repoDir, "rev-parse", "--verify", commitSHA+"^{commit}")
113		out, err := cmd.Output()
114		if err != nil {
115			return "", fmt.Errorf("git rev-parse %s: %w", commitSHA, err)
116		}
117		return strings.TrimSpace(string(out)), nil
118	}
