120	func isFullCommitSHA(commitSHA string) bool {
121		if len(commitSHA) != 40 {
122			return false
123		}
124		for i := 0; i < len(commitSHA); i++ {
125			c := commitSHA[i]
126			if c >= '0' && c <= '9' {
127				continue
128			}
129			if c >= 'a' && c <= 'f' {
130				continue
131			}
132			if c >= 'A' && c <= 'F' {
133				continue
134			}
135			return false
136		}
137		return true
138	}
